/**
 * @suppress
 */
public object FfiConverterTypePlatformBridge: FfiConverter<PlatformBridge, Long> {
    internal val handleMap = UniffiHandleMap<PlatformBridge>()

    override fun lower(value: PlatformBridge): Long {
        if (value is PlatformBridgeImpl) {
             // Rust-implemented object.  Clone the handle and return it
            return value.uniffiCloneHandle()
         } else {
            // Kotlin object, generate a new vtable handle and return that.
            return handleMap.insert(value)
         }
    }

    override fun lift(value: Long): PlatformBridge {
        if ((value and 1.toLong()) == 0.toLong()) {
            // Rust-generated handle, construct a new class that uses the handle to implement the
            // interface
            return PlatformBridgeImpl(UniffiWithHandle, value)
        } else {
            // Kotlin-generated handle, get the object from the handle map
            return handleMap.remove(value)
        }
    }

    override fun read(buf: ByteBuffer): PlatformBridge {
        return lift(buf.getLong())
    }

    override fun allocationSize(value: PlatformBridge) = 8UL

    override fun write(value: PlatformBridge, buf: ByteBuffer) {
        buf.putLong(lower(value))
    }
}



