/**
 * FFI mirror of `uc_mobile_proto::ConnectUriError` (spec §4.2 error table).
 *
 * Variant-for-variant identical; payload fields are widened to FFI-safe
 * types (`&'static str` → `String`, `usize` → `u64`).
 */
sealed class ConnectUriException: kotlin.Exception() {
    
    class InvalidScheme(
        ) : ConnectUriException() {
        override val message
            get() = ""
    }
    
    class UnsupportedVersion(
        ) : ConnectUriException() {
        override val message
            get() = ""
    }
    
    class UnsupportedService(
        ) : ConnectUriException() {
        override val message
            get() = ""
    }
    
    class PayloadDecodeFailed(
        
        val `reason`: kotlin.String
        ) : ConnectUriException() {
        override val message
            get() = "reason=${ `reason` }"
    }
    
    class MissingField(
        
        val `field`: kotlin.String
        ) : ConnectUriException() {
        override val message
            get() = "field=${ `field` }"
    }
    
    class InvalidUrl(
        ) : ConnectUriException() {
        override val message
            get() = ""
    }
    
    class UriTooLong(
        
        val `len`: kotlin.ULong, 
        
        val `max`: kotlin.ULong
        ) : ConnectUriException() {
        override val message
            get() = "len=${ `len` }, max=${ `max` }"
    }
    

    


    companion object ErrorHandler : UniffiRustCallStatusErrorHandler<ConnectUriException> {
        override fun lift(error_buf: RustBuffer.ByValue): ConnectUriException = FfiConverterTypeConnectUriError.lift(error_buf)
    }

    
}

/**
 * @suppress
 */
public object FfiConverterTypeConnectUriError : FfiConverterRustBuffer<ConnectUriException> {
    override fun read(buf: ByteBuffer): ConnectUriException {
        

        return when(buf.getInt()) {
            1 -> ConnectUriException.InvalidScheme()
            2 -> ConnectUriException.UnsupportedVersion()
            3 -> ConnectUriException.UnsupportedService()
            4 -> ConnectUriException.PayloadDecodeFailed(
                FfiConverterString.read(buf),
                )
            5 -> ConnectUriException.MissingField(
                FfiConverterString.read(buf),
                )
            6 -> ConnectUriException.InvalidUrl()
            7 -> ConnectUriException.UriTooLong(
                FfiConverterULong.read(buf),
                FfiConverterULong.read(buf),
                )
            else -> throw RuntimeException("invalid error enum value, something is very wrong!!")
        }
    }

    override fun allocationSize(value: ConnectUriException): ULong {
        return when(value) {
            is ConnectUriException.InvalidScheme -> (
                // Add the size for the Int that specifies the variant plus the size needed for all fields
                4UL
            )
            is ConnectUriException.UnsupportedVersion -> (
                // Add the size for the Int that specifies the variant plus the size needed for all fields
                4UL
            )
            is ConnectUriException.UnsupportedService -> (
                // Add the size for the Int that specifies the variant plus the size needed for all fields
                4UL
            )
            is ConnectUriException.PayloadDecodeFailed -> (
                // Add the size for the Int that specifies the variant plus the size needed for all fields
                4UL
                + FfiConverterString.allocationSize(value.`reason`)
            )
            is ConnectUriException.MissingField -> (
                // Add the size for the Int that specifies the variant plus the size needed for all fields
                4UL
                + FfiConverterString.allocationSize(value.`field`)
            )
            is ConnectUriException.InvalidUrl -> (
                // Add the size for the Int that specifies the variant plus the size needed for all fields
                4UL
            )
            is ConnectUriException.UriTooLong -> (
                // Add the size for the Int that specifies the variant plus the size needed for all fields
                4UL
                + FfiConverterULong.allocationSize(value.`len`)
                + FfiConverterULong.allocationSize(value.`max`)
            )
        }
    }

    override fun write(value: ConnectUriException, buf: ByteBuffer) {
        when(value) {
            is ConnectUriException.InvalidScheme -> {
                buf.putInt(1)
                Unit
            }
            is ConnectUriException.UnsupportedVersion -> {
                buf.putInt(2)
                Unit
            }
            is ConnectUriException.UnsupportedService -> {
                buf.putInt(3)
                Unit
            }
            is ConnectUriException.PayloadDecodeFailed -> {
                buf.putInt(4)
                FfiConverterString.write(value.`reason`, buf)
                Unit
            }
            is ConnectUriException.MissingField -> {
                buf.putInt(5)
                FfiConverterString.write(value.`field`, buf)
                Unit
            }
            is ConnectUriException.InvalidUrl -> {
                buf.putInt(6)
                Unit
            }
            is ConnectUriException.UriTooLong -> {
                buf.putInt(7)
                FfiConverterULong.write(value.`len`, buf)
                FfiConverterULong.write(value.`max`, buf)
                Unit
            }
        }.let { /* this makes the `when` an expression, which ensures it is exhaustive */ }
    }

}



