    class Network(
        
        val `reason`: kotlin.String
        ) : SyncException() {
        override val message
            get() = "reason=${ `reason` }"
    }
    
    /**
     * Swift `.authFailed` — HTTP 401.
     */
    class Unauthorized(
        ) : SyncException() {
        override val message
            get() = ""
    }
    
    /**
     * Swift `.notFound` — HTTP 404 (also the documented "empty server" GET
     * state, which callers treat as "absent", not an error).
     */
    class NotFound(
        ) : SyncException() {
        override val message
            get() = ""
    }
    
    /**
     * Swift `.serverError(status)` — HTTP 5xx.
     */
    class ServerException(
        
        val `status`: kotlin.UShort
        ) : SyncException() {
        override val message
            get() = "status=${ `status` }"
    }
    
    /**
     * Swift `.protocolError(status)` — any other non-success status (e.g.
     * other 4xx, 3xx, or a non-{200,201,204} 2xx).
     */
    class ProtocolException(
        
        val `status`: kotlin.UShort
        ) : SyncException() {
        override val message
            get() = "status=${ `status` }"
    }
    
    /**
     * Swift `.decodingFailed` — a 2xx body that did not parse as the expected
     * wire shape.
     */
    class DecodingFailed(
        
        val `reason`: kotlin.String
        ) : SyncException() {
        override val message
            get() = "reason=${ `reason` }"
    }
    
    /**
     * Swift `.cancelled` — the request was aborted via
     * [`MobileSyncClient::cancel_in_flight`] (or the caller-side future was
     * dropped). A deliberate no-op for the sync engine, not a failure.
     */
    class Cancelled(
        ) : SyncException() {
        override val message
            get() = ""
    }
    
    class Internal(
        
        val `reason`: kotlin.String
        ) : SyncException() {
        override val message
            get() = "reason=${ `reason` }"
    }
    

    


    companion object ErrorHandler : UniffiRustCallStatusErrorHandler<SyncException> {
        override fun lift(error_buf: RustBuffer.ByValue): SyncException = FfiConverterTypeSyncError.lift(error_buf)
    }

    
}

/**
 * @suppress
 */
public object FfiConverterTypeSyncError : FfiConverterRustBuffer<SyncException> {
    override fun read(buf: ByteBuffer): SyncException {
        

        return when(buf.getInt()) {
            1 -> SyncException.NotInitialized()
            2 -> SyncException.InvalidInput(
                FfiConverterString.read(buf),
                )
            3 -> SyncException.Network(
                FfiConverterString.read(buf),
                )
            4 -> SyncException.Unauthorized()
            5 -> SyncException.NotFound()
            6 -> SyncException.ServerException(
                FfiConverterUShort.read(buf),
                )
            7 -> SyncException.ProtocolException(
                FfiConverterUShort.read(buf),
                )
            8 -> SyncException.DecodingFailed(
                FfiConverterString.read(buf),
                )
            9 -> SyncException.Cancelled()
            10 -> SyncException.Internal(
                FfiConverterString.read(buf),
                )
            else -> throw RuntimeException("invalid error enum value, something is very wrong!!")
        }
    }

    override fun allocationSize(value: SyncException): ULong {
        return when(value) {
            is SyncException.NotInitialized -> (
                // Add the size for the Int that specifies the variant plus the size needed for all fields
                4UL
            )
            is SyncException.InvalidInput -> (
                // Add the size for the Int that specifies the variant plus the size needed for all fields
                4UL
                + FfiConverterString.allocationSize(value.`reason`)
            )
            is SyncException.Network -> (
                // Add the size for the Int that specifies the variant plus the size needed for all fields
                4UL
                + FfiConverterString.allocationSize(value.`reason`)
            )
            is SyncException.Unauthorized -> (
                // Add the size for the Int that specifies the variant plus the size needed for all fields
                4UL
            )
            is SyncException.NotFound -> (
                // Add the size for the Int that specifies the variant plus the size needed for all fields
                4UL
            )
            is SyncException.ServerException -> (
                // Add the size for the Int that specifies the variant plus the size needed for all fields
                4UL
                + FfiConverterUShort.allocationSize(value.`status`)
            )
            is SyncException.ProtocolException -> (
                // Add the size for the Int that specifies the variant plus the size needed for all fields
                4UL
                + FfiConverterUShort.allocationSize(value.`status`)
            )
            is SyncException.DecodingFailed -> (
                // Add the size for the Int that specifies the variant plus the size needed for all fields
                4UL
                + FfiConverterString.allocationSize(value.`reason`)
            )
            is SyncException.Cancelled -> (
                // Add the size for the Int that specifies the variant plus the size needed for all fields
                4UL
            )
            is SyncException.Internal -> (
                // Add the size for the Int that specifies the variant plus the size needed for all fields
                4UL
                + FfiConverterString.allocationSize(value.`reason`)
            )
        }
    }

    override fun write(value: SyncException, buf: ByteBuffer) {
        when(value) {
            is SyncException.NotInitialized -> {
                buf.putInt(1)
                Unit
            }
            is SyncException.InvalidInput -> {
                buf.putInt(2)
                FfiConverterString.write(value.`reason`, buf)
                Unit
            }
            is SyncException.Network -> {
                buf.putInt(3)
                FfiConverterString.write(value.`reason`, buf)
                Unit
            }
            is SyncException.Unauthorized -> {
                buf.putInt(4)
                Unit
            }
            is SyncException.NotFound -> {
                buf.putInt(5)
                Unit
            }
            is SyncException.ServerException -> {
                buf.putInt(6)
                FfiConverterUShort.write(value.`status`, buf)
                Unit
            }
            is SyncException.ProtocolException -> {
                buf.putInt(7)
                FfiConverterUShort.write(value.`status`, buf)
                Unit
            }
            is SyncException.DecodingFailed -> {
                buf.putInt(8)
                FfiConverterString.write(value.`reason`, buf)
                Unit
            }
            is SyncException.Cancelled -> {
                buf.putInt(9)
                Unit
            }
            is SyncException.Internal -> {
                buf.putInt(10)
                FfiConverterString.write(value.`reason`, buf)
                Unit
            }
        }.let { /* this makes the `when` an expression, which ensures it is exhaustive */ }
    }

}



